import React from 'react';
import { useEffect } from "react";
import { Button } from './Button';
import './Events.css';
import events2 from './events2.png';
import Metta from './Metta.png'
import Topbar from './Topbar';

function Events() {


  function ScrollToTopOnMount() {
    useEffect(() => {
      window.scrollTo(0, 0);
    }, []);

    return null;
  }

  return (
    <div className="events-container" id="events">
      <ScrollToTopOnMount />
      {/* ---Banner--- */}
      <div className='banner-container3'>
        <div className="image-banner" >
          <Topbar />
          <img src={events2} />
        </div>
      </div>
      {/* ---------------- */}
      <h1 className='apropos-title2'> Le programme Metta </h1>
      <div className="cards-content">
        <img src={Metta} className="image-yoga" />
        <div className="text-metta">
          <h3 className="title-metta"> Mais qu'est-ce que c'est ?</h3>
          <div className="content-metta">
            <p>
              Ce programme est destiné à toutes les personnes qui souhaitent aller plus loin dans votre quête de sens et vous sentir bien dans votre corps.
              Sur une période de 4 mois, vous serez suivi.e individuellement avec des sessions collectives.
              En fonction de vos besoins, vous aurez accès à une session de yoga par semaine, une session de coaching toutes les deux semaines et une session voyage au tambour par mois. Un point sera fait de façon régulière et vous aurez accès à du contenu écrit pour vous aider à bénéficier des effets du programme régulièrement.</p>
          </div>

          <h3> Pour qui ? </h3>
          <p>
            Si tu as envie de découvrir de nouveaux outils de développement personnel, que ce soit par le corps, par l'esprit ou par la parole. Si tu sens que tu as besoin d'être accompagné.e, qu'on te donne des objectifs, d'échanger et que tu es curieu.x.se d'explorer alors ce programme est fait pour toi. Il est n'est pas facile de trouver le temps et l'énergie d'avancer dans ses projets, d'y voir clair. Alors on abandonne et on laisse ses projets et problèmes de côté. Avoir un suivi permet de véritablement avancer sans se mettre de pression.
          </p>

          <h3> Comment ça se déroule ?</h3>


        </div>
      </div>
      <div className='metta-btns'>
        <Button buttonStyle='btn--outline' buttonSize='btn--large'>
          Book un premier appel !
        </Button>
      </div>
    </div>
  )
}

export default Events;
